var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"타깃을 발견했다.","JPN":"ターゲットを発見した。","ENG":"Target located.","TWN":"目標已找到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"이미 빼돌린 줄 알았는데, 이런 곳에 숨겨뒀었군.","JPN":"すでになくなっていると思っていたが、こんなところに隠しておいたとはな。","ENG":"I thought he already took it away, but he hid it here.","TWN":"還以為已經逃跑了，沒想到竟然藏在這種地方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"본부, 들리나? 타깃 회수를 위해 지원병력을 요청한다.","JPN":"本部に伝える。ターゲットの回収のため、兵力の追加支援を求む。","ENG":"HQ, do you copy? Requesting reinforcements to assist with the retrieval.","TWN":"總部，能聽到我說話嗎？為了帶回目標，請求增援。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"이런. 송신상태가 불량인가?","JPN":"くっ、通信状況が芳しくないようだ。","ENG":"Damn. Are the comms out?","TWN":"可惡。傳輸訊號不好嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"뭐야? 무슨 일이야?","JPN":"なんだ？　何が起きた？","ENG":"What? What’s going on?","TWN":"什麼？怎麼了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"매복이다! 놈이 눈치챘어!","JPN":"待ち伏せだ！　奴に気づかれていたぞ！","ENG":"It's an ambush! We've been found!","TWN":"有埋伏！發現那傢伙了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"쏴! 쏘라고!","JPN":"撃て！　撃ちまくれ！","ENG":"Fire! Return fire!","TWN":"射擊！快射擊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식체한테 당한 건 아니네요. 이건 탄환이 뚫고 간 자국이에요.","JPN":"これは侵食体にやられた傷跡じゃありません。弾丸に撃ち抜かれた痕です。","ENG":"This wasn't a C.O.'s doing. These are bullet holes.","TWN":"不是被侵蝕體襲擊的。這是子彈穿過的痕跡。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"와아, 이 사람은 폐를 관통 당했네요.","JPN":"わあ、この人は肺に穴を開けられたみたいです。","ENG":"Wow, this person got his lungs pierced.","TWN":"哇，這傢伙的肺被打穿了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"분명 엄청 괴로워하면서 죽었겠죠?","JPN":"きっと、すごく苦しい死に方をしたでしょうね。","ENG":"He must've suffered a lot.","TWN":"他一定死得很痛苦吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금 블랙박스기록 확인했어. 선발대는 누군가의 습격을 받은 게 맞아.","JPN":"さっきブラックボックスの記録は確認した。先発隊は何者かに襲撃を受けたに違いない。","ENG":"I just checked the black box records. The advance party was ambushed by someone.","TWN":"我剛剛查了一下黑盒記錄。先遣隊確實被人襲擊了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"습격자는 아마도 우리가 쫓고 있는 의뢰 타깃이겠지.","JPN":"襲撃したのは……おそらく私たちが追いかけているターゲットと同じ人物のはずだ。","ENG":"The ambusher must be the target we're after.","TWN":"襲擊者很可能就是我們所追查的委託目標。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"무기를 가지고 있다면, 평화적인 방법으로 데려가긴 어렵겠네요.","JPN":"相手が武器を持っているなら、平和的に連れて帰るのは難しそうですね。","ENG":"If this person is armed, we might face some resistance.","TWN":"如果他攜帶著武器，我們很難和平地帶走他。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…그래. 상처없이 제압하라곤 안 할 테니 죽이지만 마.","JPN":"……そうだな。無傷でとは言わないが、生かして捕らえろ。","ENG":"...Yeah. I won't tell you not to hurt him, but just don't kill him.","TWN":"……我知道。讓他受點傷沒什麼關係，只要不殺掉就可以了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"전 다쳐도 돼요. 원하시면 최대한 건강한 상태로 붙잡아볼게요.","JPN":"私はいくら怪我をしても大丈夫ですので、相手にはできるだけ傷を与えずに捕まえてみます。","ENG":"I don't mind getting hurt. I'll try to take him down without hurting him.","TWN":"我倒是不介意受傷。如果是你的要求，我會盡力不傷著他。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그 분이 만약 스펜서를 노린다면, 저도 공격하는 수밖에 없겠지만요.","JPN":"でもスペンサーさんが狙われたその時は、しかたないので攻撃しますよ。","ENG":"But if he attacks you, Spencer, I'll have no choice but to fight back.","TWN":"但如果他要攻擊你，史賓瑟，那我也只能還擊了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"목숨을 내버리면서까지 무리할 일은 아니야.","JPN":"命をかけてもらうほどのことではない。","ENG":"It's not worth throwing away your life over.","TWN":"不需要你犧牲自己。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 좋은 카운터 능력도 이터니움이 떨어져버리면 쓸 수 없게 된다며?","JPN":"素晴らしいカウンターの能力を持っているのに、エタニウムがないと発動できなくなるんだって？","ENG":"I hear you can't use your remarkable Counter ability if you run out of Eternium, no?","TWN":"當永恆之金耗盡時，制裁者就無法使用能力了吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"무슨 위험한 일을 하든, 일단 살고 봐야지. 안 그래?","JPN":"どんな危険な仕事だろうと、死んでしまったら意味がない、違うか？","ENG":"Whatever dangerous thing you do, live to fight another day first, okay?","TWN":"無論你準備冒什麼險，先考慮活下來的事情。好嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서는 차가운 척하지만 실은 마음이 따뜻한 사람이네요.","JPN":"スペンサーさんって、冷たいようで実は温かい方なんですね。","ENG":"You act cold but you're actually a kind person, Spencer.","TWN":"史賓瑟，你雖然看起來冷酷，但其實是個溫柔的人呢。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"마음대로 생각해.","JPN":"私はどう思われたっていい。","ENG":"Whatever.","TWN":"隨你怎麼想。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서? 선발대가 갖고 있던 총을 챙기려고요?","JPN":"スペンサーさん？　どうして先発隊の銃を手に取るんですか？","ENG":"Spencer? You're picking up the advance party's gun?","TWN":"史賓瑟？你拿著先遣隊的槍做什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그건 침식체한텐 별로 효과 없을 텐데.","JPN":"それは、たぶん侵食体には効かないと思いますよ。","ENG":"It won't be very useful against C.O.s.","TWN":"這東西對侵蝕體作用不大。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"역시 그렇지?","JPN":"やはりそうか？","ENG":"Yeah, I know.","TWN":"果然嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"선발대가 맡은 의뢰가 우리와 같다면, 어째서 이런 대인살상용 무기를 챙긴 걸까?","JPN":"先発隊が私たちと同じ依頼を受けてここに来ていたのなら、いったいどうして対人用の殺傷武器を身に着けていたのだろうか？","ENG":"If the advance party had the same job as us, why did they bring conventional weapons with them?","TWN":"如果先遣隊的任務和我們一樣的話，他們為什麼要攜帶這種對人的武器呢？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그러게요?","JPN":"ですよね？","ENG":"Good point.","TWN":"對吼？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침입자를 꼭 살려서 데려오라고 한 적은 없으니까- 라고 생각했던 건 아닐까요?","JPN":"侵入者の生存が必須条件ではないってことだったんじゃないでしょうか？","ENG":"Maybe they didn't need to bring this intruder back alive?","TWN":"你該不會是覺得他們從來沒有打算把入侵者活著帶回來吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……わかったわ。","ENG":"...Yeah.","TWN":"……嗯。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가 너무 복잡하게 생각한 걸지도 모르겠네.","JPN":"私が複雑に考えすぎてしまったようだ。","ENG":"Maybe I'm reading too much into this.","TWN":"也許是我把事情想得太複雜了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"앗, 같이 가요! 스펜서!","JPN":"あっ、ちょっと待ってください！　スペンサーさん！","ENG":"Hey, wait for me! Spencer!","TWN":"啊，等等我！史賓瑟！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"오는 길목에 표시등을 박아 놔서 망정이지. 아니면 나가는 길도 못 찾을 뻔했어.","JPN":"道に印をつけておかなかったら、出口まで永遠に彷徨っていたかもな。","ENG":"Good thing we put down the guiding lights on our way here. Or else we'd be lost.","TWN":"幸好來的路上安裝了指示燈。不然我們連出去的路都找不到。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"정말로 승강기를 탈 건가?","JPN":"本当に昇降機に乗って戻るのか？","ENG":"Are we really getting on that elevator?","TWN":"你準備就這麼坐升降機回去了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"계약내용을 잊진 않았겠지? 성과 없이 돌아가면 의뢰인이 우릴 가만두지 않을 거다.","JPN":"契約内容、覚えてるだろ？　成果なしに戻ったら、依頼人は黙っちゃいねえぞ。","ENG":"You didn't forget our contract, did you? If we return without any results, we'll be in for a world of hurt.","TWN":"你忘了合約的細節了嗎？如果我們兩手空空地回去，委託人是不會放過我們的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"아, 이제 와서 왜 이래? 어차피 대장이 거기 빠져죽은 시점에서 의뢰는 실패잖아.","JPN":"今更何を言ってんだお前？　隊長が墜落死した時点で、任務は失敗だろう。","ENG":"Aw, come on. We failed our mission the moment our captain fell.","TWN":"得了吧，現在說這些又有什麼用？反正從隊長摔下去死掉的那刻起，委託就失敗了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"아니면 우리 힘만으로 침입자를 찾아서 데려갈 수 있어?","JPN":"俺たちだけで侵入者を連れて帰れると思うか？","ENG":"Or what? You think we can bring back the intruder with just us two?","TWN":"難道就靠我們兩個找到入侵者，把他帶回去嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"거 보라고. 자기도 자신 없으면서 괜히 망설이긴.","JPN":"ほらみろ。できる自信がないのはお互い様だ。今更迷うんじゃねえよ。","ENG":"That's what I thought. You don't think we can do it either.","TWN":"你看吧。你也沒有自信，那還猶豫什麼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"어이… 네 뒤를 봐.","JPN":"おい……後ろ。","ENG":"Hey... Look behind you.","TWN":"喂……看你後面。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"Huh...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_DEAD_TEAM1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"지알로…?","JPN":"ジャッロなのか……？","ENG":"Giallo...?","TWN":"賈洛……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐야? 죽은 게 아니었어? 어떻게 된 거야?","JPN":"いったいどういうことだ？　確か死んでいたはずだろう？","ENG":"You're alive? What happened?","TWN":"什麼？他不是死了嗎？怎麼回事？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_DEAD_TEAM1","text":{"KOREA":"<color=#ff3636>돌아… 가… 죽, 어…</color>","JPN":"<color=#ff3636>帰……って……死、ね……</color>","ENG":"<color=#ff3636>Go… back… die…</color>","TWN":"<color=#ff3636>回……去，死……</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_40"},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐라고 중얼거리는 거야? 잘 안 들려.","JPN":"ぶつぶつ何って言ってんだ？　聞こえねえぞ。","ENG":"What are you saying? I can't hear you.","TWN":"他在嘀咕什麼？你聽清楚了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_DEAD_TEAM1","text":{"KOREA":"<color=#ff3636>…에게, 신선한… 피르으을…</color>","JPN":"<color=#ff3636>……様に……新鮮な……血を……</color>","ENG":"<color=#ff3636>…fresh blood… to…</color>","TWN":"<color=#ff3636>……獻上，新鮮的……血……</color>"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_DEAD_TEAM1","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_FALL_START"},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이 미친 자식이?! 갑자기 왜 날 쏘는 거야!","JPN":"おい、てめぇ正気か！？　どうして俺に向かって撃ってきやがる！","ENG":"Are you crazy?! Why are you shooting me?!","TWN":"這個瘋子？！為什麼突然向我開槍？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"저리 비켜!","JPN":"どけ！","ENG":"Out of the way!","TWN":"快躲開！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"주, 죽인 거야?","JPN":"こ、殺したのか？","ENG":"You killed him?","TWN":"死、死了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"어이, 저놈 슈트 벗겨봐.","JPN":"おいっ、あいつのスーツ脱がしてみろ。","ENG":"Hey, take off his suit.","TWN":"喂，把那傢伙的衣服脫掉。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐? 내가…?","JPN":"はあ？　何で俺が？","ENG":"What? Me...?","TWN":"什麼？我……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"에이씨…","JPN":"わかったよ……","ENG":"Argh...","TWN":"真是的……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐야, 이 녀석. 피부가 시퍼런 게 무슨 미라마냥 말라붙어 있는데?","JPN":"なんだこいつ。肌がミイラみたいに真っ青になって干からびてるぞ。","ENG":"What the– His skin's all blue and dried up like a mummy.","TWN":"這傢伙搞什麼？皮膚又青又乾，像木乃伊一樣？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"넌 이런 걸 전에도 본 적 있나?","JPN":"こんなの見たことあるか？","ENG":"Have you seen anything like this?","TWN":"你以前見過這樣的事情嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"어… 글쎄? 창고에 갇힌 채로 아사한 노숙자가 한달 뒤에 발견됐을 때 딱 이런 꼴이었던 것 같은데.","JPN":"えっと、そうだな……倉庫に閉じ込められて餓死したホームレスがまさにこんな感じだった気はするが。","ENG":"Uh... I don't think so? I think I remember seeing something similar when a homeless guy got stuck in a warehouse and was found like this a month later.","TWN":"呃……應該有吧？之前有個被關在倉庫裡餓死的流浪者，一個月後被發現時，好像就是這個樣子。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이 목의 상처는… 거칠지만 정확하게 경동맥을 노린 흔적이다.","JPN":"首にあるこの傷……粗っぽいが正確に頸動脈を狙った痕だ。","ENG":"The wound on his neck... It's a bit rough, but it went right through the jugular.","TWN":"他脖子上的傷……這個痕跡雖然粗糙，但卻對準了頸動脈。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"침식체는 이렇게 사람의 약점만 골라서 노리진 않아.","JPN":"侵食体が人間の弱点だけを狙って攻撃するなんてありえないぜ。","ENG":"C.O.s don't go for a weak spot like this.","TWN":"侵蝕體可不會挑人的弱點攻擊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"거 참 사람 불안하게 만드네. 뭔소리가 하고 싶은 건데?","JPN":"不安になるようなことばかり言いやがって、何が言いたいんだ？","ENG":"You're making me nervous. What are you trying to say?","TWN":"真是讓人不安。你到底想說什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"우선 승강기에 타자고.","JPN":"とりあえず昇降機に乗ろうぜ。","ENG":"Let's get on the elevator first.","TWN":"我們還是先搭升降機上去吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"쳇, 싱겁긴.","JPN":"ちっ、なんだそれ、シラケんな。","ENG":"Tch. Yeah, whatever.","TWN":"嘖，沒意思。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"음…? 왜 작동이 안되지?","JPN":"うん……？　なんで動かないんだ？","ENG":"Huh...? Why's it not working?","TWN":"唔……？為什麼啟動不了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"잠깐. 계기판에 불이 안 들어오잖아?","JPN":"おい、待て。計器盤に電源が入らなくなってるぞ？","ENG":"Hold on. The panel's not turning on.","TWN":"等等。儀錶板上的燈不亮了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"녀석이 노리고 쏜 건, 애초에 사람이 아니었군.","JPN":"あいつ、最初から俺たちを撃つつもりなどなかったみたいだ。","ENG":"He wasn't aiming for you in the first place.","TWN":"那傢伙一開始瞄準的就不是你。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"승강기의 컨트롤 패널을 정확하게 노렸어.","JPN":"昇降機のパネルを狙って撃っていたんだ。","ENG":"He nailed the elevator's control panel.","TWN":"而是這個升降機的控制台。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"…말이 돼? 갑자기 죽었던 시체가 걸어오더니 우리가 집으로 갈 유일한 방법을 부쉈다고?","JPN":"……バカ言えよ。死体が歩いてきたうえに、俺たちが帰れる唯一の手段をぶっ壊したって？","ENG":"...That's nonsense. A corpse walked all the way here just to bust our only way home?","TWN":"這……這沒道理啊？一具活了的屍體突然走過來，毀掉了我們回去唯一的路？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이런 개소릴 누가 믿겠어?","JPN":"そんな馬鹿げた話、あるかよ！","ENG":"Who's gonna believe this nonsense?","TWN":"誰會相信這種鬼話？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"어쩌면 우리가 나온 곳에 탈출을 위한 비상수단이 있을 지도 모르지.","JPN":"まだどこかに非常用の脱出手段があるかもしれない。","ENG":"Maybe there's an emergency escape at the place we escaped from.","TWN":"也許我們出來的地方有緊急逃生艙。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그, 그렇구만! 그 정도로 큰 이면세계 시설이라면, 어딘가에 현실부상용 포드 정도는 있을 거야. 안 그래?","JPN":"そ、そうだな！　裏世界にこんなデカい施設を建てたんだから、脱出ポートぐらいあるよな？","ENG":"Y-yeah! A facility that big in the Counterside, there must be an escape pod going to the Normalside somewhere, right?","TWN":"是啊，沒錯！這麼大的異界設施，一定會在某處有一個躍出分離艙。是不是？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"지금으로선 거기에 걸어보는 수 밖에.","JPN":"この状況ではそれにかけるしかない。","ENG":"Guess we have no choice but to bet on that.","TWN":"我們只能回去看看了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};